+                std::ptr::copy_nonoverlapping(src, dst.add(dst_len), copy_len);
+            }
+            *dst.add(dst_len + copy_len) = 0;
+            (dst_len + copy_len + 1, false)
+        }
+    };
+
+    runtime_policy::observe(
+        ApiFamily::StringMemory,
+        decision.profile,
+        runtime_policy::scaled_cost(9, work * 4),
+        adverse,
